const formatFlightMoment = (value) => {
  if (!value) return "Flexible schedule";

  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return "Flexible schedule";

  return new Intl.DateTimeFormat("en-US", {
    month: "short",
    day: "numeric",
    hour: "numeric",
    minute: "2-digit",
  }).format(date);
};

