                <p className="text-xs font-black uppercase tracking-[0.2em]">Travel Class</p>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                {classOptions.map((option) => {
                  const isActive = selectedClass === option.value;
                  return (
                    <motion.button
                      whileHover={{ y: -2 }}
